#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (int i = 0; i < n; ++i) {
        cin >> arr[i];
    }

    vector<int> unique_elements;
    unordered_set<int> seen;

    for (int x : arr) {
        if (seen.find(x) == seen.end()) {
            unique_elements.push_back(x);
            seen.insert(x);
        }
    }

    for (int i = 0; i < unique_elements.size(); ++i) {
        cout << unique_elements[i] << (i == unique_elements.size() - 1 ? "" : " ");
    }
    cout << endl;

    return 0;
}

