#include <stdio.h>
#include <stdbool.h>

int main() {
    int n;
    scanf("%d", &n);
    int arr[n], unique_elements[n];
    bool seen[100000] = {false};
    int unique_count = 0;

    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    for (int i = 0; i < n; i++) {
        if (!seen[arr[i]]) {
            unique_elements[unique_count++] = arr[i];
            seen[arr[i]] = true;
        }
    }

    for (int i = 0; i < unique_count; i++) {
        printf("%d", unique_elements[i]);
        if (i != unique_count - 1) printf(" ");
    }
    printf("\n");
    return 0;
}

